  if (dist_index > 1) {
    lzma_state->dists[2] = lzma_state->dists[1];
  }
  if (dist_index > 0) {
    lzma_state->dists[1] = lzma_state->dists[0];
  }
  lzma_state->dists[0] = dist;
}
