impl<'a> SubstringEnumerator<'a> {
    pub fn memory_usage(data_size: usize) -> usize {
        std::mem::size_of::<usize>() * data_size + std::mem::size_of::<SubstringEnumerator>()
    }

    pub fn new(data: &'a [u8], min_length: usize, max_length: usize) -> Self {
        assert_eq!(min_length, 2, "Only min_length=2 is supported");

        let mut enumerator = SubstringEnumerator {
            data,
            min_length,
            max_length,
            bigram_offsets: [[0; 256]; 256],
            bigram_sizes: [[0; 256]; 256],
            bigram_positions: vec![0; data.len()],
        };

        // Count bigrams
        for i in 1..data.len() {
            let first = data[i - 1] as usize;
            let second = data[i] as usize;
            enumerator.bigram_sizes[first][second] += 1;
        }

        // Calculate offsets
        for i in 1..(256 * 256) {
            let j = i - 1;
            let first_i = i % 256;
            let second_i = i / 256;
            let first_j = j % 256;
            let second_j = j / 256;
            enumerator.bigram_offsets[first_i][second_i] = 
                enumerator.bigram_offsets[first_j][second_j] + 
                enumerator.bigram_sizes[first_j][second_j];
        }

        // Fill positions
        let mut fills = [[0; 256]; 256];
        for i in 1..data.len() {
            let first = data[i - 1] as usize;
            let second = data[i] as usize;
            let offset = enumerator.bigram_offsets[first][second] + fills[first][second];
            enumerator.bigram_positions[offset] = i - 1;
            fills[first][second] += 1;
        }

        enumerator
    }

    /// For a given position `pos` (the "current" start), call the callback for each previous substring
    /// (starting at some index < pos) that matches the substring beginning at pos.
    pub fn for_each<F>(&self, pos: usize, mut callback: F)
    where
        F: FnMut(usize, usize),
    {
        if pos == 0 || pos >= self.data.len() - 1 {
            return;
        }

        let first = self.data[pos] as usize;
        let second = self.data[pos + 1] as usize;
        let offset = self.bigram_offsets[first][second];
        let size = self.bigram_sizes[first][second];

        for i in 0..size {
            let position = self.bigram_positions[offset + i];

            // Skip if position is not before pos
            if position >= pos {
                continue;
            }

            callback(position, 2);

            // Extend the match as far as possible
            for j in 2..std::cmp::min(self.max_length, self.data.len() - pos) {
                // Check bounds before accessing data
                if position + j >= self.data.len() {
                    break;
                }
                if self.data[pos + j] != self.data[position + j] {
                    break;
                }
                callback(position, 1 + j);
            }
        }
    }
}
