impl<'a> TopKPacketFinder<'a> {
    pub fn new(size: usize, packet_enumerator: &'a PacketEnumerator<'a>) -> Self {
        let entries = Rc::new(RefCell::new(vec![TopKEntry { packet: LZMAPacket::literal_packet(), cost: 0.0 }; size]));
        let comparator_entries = entries.clone();
        let comparator = Box::new(move |a: u32, b: u32| {
            let entries = comparator_entries.borrow();
            let cost_a = entries[a as usize].cost;
            let cost_b = entries[b as usize].cost;
            if cost_a < cost_b { -1 } else if cost_a > cost_b { 1 } else { 0 }
        });

        TopKPacketFinder {
            size,
            entries,
            heap: RefCell::new(MaxHeap::new(size, comparator)),
            packet_enumerator,
        }
    }

    pub fn count(&self) -> usize {
        self.heap.borrow().count()
    }

    pub fn find(&self, lzma_state: &LZMAState, next_packets: &mut [LZMAPacket]) {
        self.heap.borrow_mut().clear();

        let entries = self.entries.clone();
        let heap = self.heap.clone();
        let size = self.size;

        self.packet_enumerator.for_each(lzma_state, |state, packet| {
            // Compare with next_packets to avoid duplicate work
            if LZMAPacket::cmp(&packet, &next_packets[state.position]) {
                return;
