            // Calculate cost by simulating encoding
            let mut new_state = state.clone();
            let mut perplexity = 0u64;
            let mut enc = PerplexityEncoder::new(&mut perplexity);
            let start_position = new_state.position;
            lzma_encode_packet(&mut new_state, &mut enc, packet);

            let length = new_state.position - start_position;
            let cost = if length > 0 { perplexity as f32 / length as f32 } else { 0.0 };

            let entry = TopKEntry { packet, cost };

            // Insert into heap
            let mut heap = heap.borrow_mut();
            let count = heap.count();

            if count < size {
                // If there is room, just insert
                let mut entries = entries.borrow_mut();
                entries[count] = entry;
                heap.insert(count as u32);
            } else {
                // Otherwise, we must compare with the maximum and replace if needed
                if let Some(maximum) = heap.maximum() {
                    let maximum = maximum as usize;
                    let entries = entries.borrow();
                    if entry.cost <= entries[maximum].cost {
                        drop(entries);
                        let mut entries = entries.borrow_mut();
                        entries[maximum] = entry;
                        heap.update_maximum();
                    }
                }
            }
        });
