    pub fn new(size: usize, packet_enumerator: &'a PacketEnumerator<'a>) -> Self {
        let entries = Rc::new(RefCell::new(vec![TopKEntry { packet: LZMAPacket::literal_packet(), cost: 0.0 }; size]));

