        self.heap.borrow().count()
    }

    pub fn find(&self, lzma_state: &LZMAState, next_packets: &mut [LZMAPacket]) {
        self.heap.borrow_mut().clear();

        self.packet_enumerator.for_each(lzma_state, |state, packet| {
            // Compare with next_packets to avoid duplicate work
            if LZMAPacket::cmp(&packet, &next_packets[state.position]) {
                return;
