    bigram_offsets: [[usize; 256]; 256],
    bigram_sizes: [[usize; 256]; 256],
    bigram_positions: Vec<usize>,
}

impl<'a> SubstringEnumerator<'a> {
    pub fn memory_usage(data_size: usize) -> usize {
        std::mem::size_of::<usize>() * data_size + std::mem::size_of::<SubstringEnumerator>()
    }

    pub fn new(data: &'a [u8], min_length: usize, max_length: usize) -> Self {
        assert_eq!(min_length, 2, "Only min_length=2 is supported");

        let mut enumerator = SubstringEnumerator {
            data,
            min_length,
            max_length,
            bigram_offsets: [[0; 256]; 256],
            bigram_sizes: [[0; 256]; 256],
            bigram_positions: vec![0; data.len()],
        };

        // Count bigrams
        for i in 1..data.len() {
            let first = data[i - 1] as usize;
            let second = data[i] as usize;
            enumerator.bigram_sizes[first][second] += 1;
        }

        // Calculate offsets
        for i in 1..(256 * 256) {
            let j = i - 1;
            let first_i = i % 256;
            let second_i = i / 256;
            let first_j = j % 256;
            let second_j = j / 256;
            enumerator.bigram_offsets[first_i][second_i] = 
